package org.apache.commons.csv;
import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.Closeable;
import java.io.FileInputStream;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.io.StringReader;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;
import java.util.TreeMap;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedReader;
import java.io.File;
import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;
import java.net.URL;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserParseTest {

    private CSVFormat mockFormat;
    private Charset charset;

    @BeforeEach
    void setUp() {
        mockFormat = mock(CSVFormat.class);
        charset = Charset.defaultCharset();
    }

    @Test
    void parse_Path_NullPath_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((Path) null, charset, mockFormat));
        assertTrue(ex.getMessage().contains("path"));
    }

    @Test
    void parse_Path_NullFormat_Throws() throws IOException {
        Path mockPath = mock(Path.class);
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(mockPath, charset, null));
        assertTrue(ex.getMessage().contains("format"));
    }

    @Test
    void parse_Path_DelegatesToReader() throws Exception {
        Path mockPath = mock(Path.class);
        BufferedReader mockReader = mock(BufferedReader.class);

        // Mock Files.newBufferedReader(path, charset)
        // Using reflection to replace Files.newBufferedReader behavior
        // since Mockito 3 does not support mockStatic

        // Create a subclass of CSVParser to override parse(Reader, CSVFormat)
        class CSVParserTestSubclass extends CSVParser {
            protected CSVParserTestSubclass() {
                super(mockReader, mockFormat);
            }
        }

        // Create expected parser instance
        CSVParser expectedParser = new CSVParserTestSubclass();

        // Use reflection to replace CSVParser.parse(Reader, CSVFormat) method call
        // Here we use a spy on CSVParser class instance to simulate parse(Reader, CSVFormat)
        // but since parse(Reader, CSVFormat) is static, we cannot spy it easily with Mockito 3

        // So instead, test the parse(Path, Charset, CSVFormat) method by mocking Files.newBufferedReader
        // To do this, use a custom Path and override Files.newBufferedReader via a temporary workaround:

        // Use a wrapper class to simulate Files.newBufferedReader
        class FilesWrapper {
            BufferedReader newBufferedReader(Path path, Charset cs) throws IOException {
                return mockReader;
            }
        }
        FilesWrapper filesWrapper = new FilesWrapper();

        // Use reflection to replace Files.newBufferedReader call in CSVParser.parse(Path, Charset, CSVFormat)
        // Since we cannot replace static calls directly, invoke parse(Path, Charset, CSVFormat) and
        // verify the returned parser is not null (integration test)

        // Instead, run parse(Path, Charset, CSVFormat) and verify it returns a non-null CSVParser
        // but we cannot mock static methods in Mockito 3, so just test for exception and non-null

        // This is a limitation due to no mockStatic support in Mockito 3

        // So just test that parse(Path, Charset, CSVFormat) does not throw and returns non-null
        // when given real parameters

        // Provide a temp file for this test
        Path tempFile = java.nio.file.Files.createTempFile("csvparser_test", ".csv");
        try {
            // Write some content to temp file
            java.nio.file.Files.write(tempFile, "a,b,c\n1,2,3\n".getBytes(charset));

            CSVParser actual = CSVParser.parse(tempFile, charset, CSVFormat.DEFAULT);
            assertNotNull(actual);
            actual.close();
        } finally {
            java.nio.file.Files.deleteIfExists(tempFile);
        }
    }

    @Test
    void parse_File_NullFile_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((File) null, charset, mockFormat));
        assertTrue(ex.getMessage().contains("file"));
    }

    @Test
    void parse_File_NullFormat_Throws() {
        File file = mock(File.class);
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(file, charset, null));
        assertTrue(ex.getMessage().contains("format"));
    }

    @Test
    void parse_InputStream_NullInputStream_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((java.io.InputStream) null, charset, mockFormat));
        assertTrue(ex.getMessage().contains("inputStream"));
    }

    @Test
    void parse_InputStream_NullFormat_Throws() {
        java.io.InputStream is = mock(java.io.InputStream.class);
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(is, charset, null));
        assertTrue(ex.getMessage().contains("format"));
    }

    @Test
    void parse_Reader_NullReader_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((Reader) null, mockFormat));
        assertTrue(ex.getMessage().contains("reader"));
    }

    @Test
    void parse_Reader_NullFormat_Throws() {
        Reader reader = mock(Reader.class);
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(reader, null));
        assertTrue(ex.getMessage().contains("format"));
    }

    @Test
    void parse_String_NullString_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((String) null, mockFormat));
        assertTrue(ex.getMessage().contains("string"));
    }

    @Test
    void parse_String_NullFormat_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse("a,b,c", null));
        assertTrue(ex.getMessage().contains("format"));
    }

    @Test
    void parse_URL_NullURL_Throws() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse((URL) null, charset, mockFormat));
        assertTrue(ex.getMessage().contains("url"));
    }

    @Test
    void parse_URL_NullFormat_Throws() {
        URL url = mock(URL.class);
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(url, charset, null));
        assertTrue(ex.getMessage().contains("format"));
    }

}
